import { Component } from "react";
import "./Navbarstyles.css";
import "./src/assets/logo1.png";

class navbar extends Component {
   state = { clicked: false };
   handleClick =() => {
    this.setState({clicked: !this.state.clicked})
   }
   render() {

   return (
    <>
        <nav>
            <div id = "desktop" onClick={this.handleClick}>
                <i id="bar" className={this.state.clicked ? 'fas fa-times' : 'fas fa-bars'}>
                </i>
            </div>
            <a href = "index.html">
                <img src="logo1" width="161" height="44" viewBox="0 0 161 44" fill="none" alt="fireSpot"/>
            </a>
            <div>
               <ul id ="navbar">
                    <li><a className="active"
                    href = "index.html">Home</a></li>
                    <li><a href = "index.html">Services</a></li>    
                    <li><a href = "index.html">Zipcode</a></li>    
                    <li><a href = "index.html">Login/Register</a></li>    
                </ul> 
            </div>
            
        </nav>
        </>
    )
}
}

export default navbar;
